svg.script:
//
(function() {
  var svg         = document.getElementById('root');
  var ns          = 'http://www.w3.org/2000/svg';
  var dataLayerEl = document.getElementById('data-layer');
  var dotsL       = document.getElementById('dots-layer');
  var hitLayer    = document.getElementById('hit-layer');
  var tipLayer    = document.getElementById('tip-layer');

  /* §2 — isDark hoisted before all build and animation code */
  var isDark = false;

  var series = [
    { id:1, cls:'series-1', label:'Cyan',
      vals:[0,0,0,55,80,70,50,65], ys:[504.0,504.0,504.0,281.8,180.8,221.2,302.0,241.4] },
    { id:2, cls:'series-2', label:'Violet',
      vals:[20,45,70,55,35,75,85,72], ys:[423.2,322.2,221.2,281.8,362.6,201.0,160.6,213.1] },
    { id:3, cls:'series-3', label:'Emerald',
      vals:[0,30,55,80,60,40,0,0], ys:[504.0,382.8,281.8,180.8,261.6,342.4,504.0,504.0] },
    { id:4, cls:'series-4', label:'Amber',
      vals:[15,50,18,25,55,30,45,60], ys:[443.4,302.0,431.3,403.0,281.8,382.8,322.2,261.6] },
    { id:5, cls:'series-5', label:'Slate',
      vals:[55,25,23,26,24,27,22,25], ys:[281.8,403.0,411.1,399.0,407.0,394.9,415.1,403.0] },
  ];

  var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
  var xs   = [68,180,291,403,515,627,738,850];
  var colW = 56;
  var allTips = {};

  // For column tooltip: still useful to show all series values on hover
  var totals = xs.map(function(_,qi){
    return series.reduce(function(s,sr){ return s + sr.vals[qi]; }, 0);
  });

  function el(tag, attrs) {
    var e = document.createElementNS(ns, tag);
    Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
    return e;
  }

  // Mark only the series closest to mouseY active; dim the rest
  function setSeriesActive(qi, mouseY) {
    // stale-clear all
    svg.querySelectorAll('.wave-edge, .area-fill').forEach(function(e) { e.classList.remove('active'); });
    // find closest series to mouseY at this column
    var bestSid = series[0].id, bestDist = Infinity;
    series.forEach(function(s) {
      var dist = Math.abs(s.ys[qi] - mouseY);
      if (dist < bestDist) { bestDist = dist; bestSid = s.id; }
    });
    // activate matching wave-edge and area-fill
    var we = svg.querySelector('.wave-edge[data-series="'+bestSid+'"]');
    var af = svg.querySelector('.area-fill[data-series="'+bestSid+'"]');
    if (we) we.classList.add('active');
    if (af) af.classList.add('active');
    // also mark col-dots for the hovered column
    dotsL.querySelectorAll('.col-dot[data-col="'+qi+'"]').forEach(function(d) { d.classList.add('active'); });
  }
  function clearSeriesActive() {
    svg.querySelectorAll('.wave-edge, .area-fill').forEach(function(e) { e.classList.remove('active'); });
  }

  xs.forEach(function(x, qi) {
    series.forEach(function(s) {
      var dot = el('circle', {
        cx:x, cy:s.ys[qi], r:4,
        'class':'col-dot ' + s.cls,
        style:'stroke:none', 'data-col':qi
      });
      dotsL.appendChild(dot);
    });
  });

  xs.forEach(function(x, qi) {
    var PAD = 16, DOT_R = 4, DOT_X = 14, LBL_X = 26, bCy = 200, rxB = 10;
    var rowH = 18, hdrH = 20, divH = 8, totH = 20;
    var bh = hdrH + divH + series.length * rowH + divH + totH + PAD;

    var tipG = el('g', { 'class':'tip', id:'tip_'+qi });
    tipLayer.appendChild(tipG);
    allTips[qi] = tipG;

    // ── build text nodes first (local coords, x=0) so getBBox() measures real widths ──
    var qLbl = el('text', { x:0, y:bCy + hdrH/2,
      'text-anchor':'middle', 'dominant-baseline':'central', 'class':'tip-label' });
    qLbl.textContent = quarters[qi];
    tipG.appendChild(qLbl);

    var rowEls = [];
    series.forEach(function(s, si) {
      var rowY = bCy + hdrH + divH + si * rowH + rowH/2;
      var dot  = el('circle', { cx:0, cy:rowY, r:DOT_R, 'class':s.cls, style:'stroke:none' });
      var sLbl = el('text', { x:LBL_X, y:rowY, 'dominant-baseline':'central', 'class':'tip-label' });
      sLbl.textContent = s.label;
      var sVal = el('text', { x:0, y:rowY, 'text-anchor':'end', 'dominant-baseline':'central',
        'class':'tip-value', 'font-size':'11' });
      sVal.textContent = '$'+s.vals[qi]+'M';
      tipG.appendChild(dot); tipG.appendChild(sLbl); tipG.appendChild(sVal);
      rowEls.push({ dot:dot, sLbl:sLbl, sVal:sVal });
    });

    var totY = bCy + hdrH + divH + series.length * rowH + divH + totH/2;
    var totLbl = el('text', { x:LBL_X, y:totY, 'dominant-baseline':'central', 'class':'tip-label' });
    totLbl.textContent = 'Total';
    var totVal = el('text', { x:0, y:totY, 'text-anchor':'end', 'dominant-baseline':'central', 'class':'tip-value' });
    totVal.textContent = '$'+totals[qi]+'M';
    tipG.appendChild(totLbl); tipG.appendChild(totVal);

    // ── measure with getBBox() to compute hw ──
    var maxLblW = 0;
    rowEls.forEach(function(r) { maxLblW = Math.max(maxLblW, LBL_X + r.sLbl.getBBox().width + 8); });
    maxLblW = Math.max(maxLblW, LBL_X + totLbl.getBBox().width + 8);
    var maxValW = 0;
    rowEls.forEach(function(r) { maxValW = Math.max(maxValW, r.sVal.getBBox().width); });
    maxValW = Math.max(maxValW, totVal.getBBox().width);
    var hw = Math.max((maxLblW + maxValW) / 2 + PAD, 80);

    // ── clamp centre-x to card bounds ──
    var bCx = Math.max(hw + 8, Math.min(x, 1100 - hw - 8));

    // ── translate group; reposition all elements relative to bCx ──
    tipG.setAttribute('transform', 'translate('+bCx+',0)');
    qLbl.setAttribute('x', '0');
    rowEls.forEach(function(r) {
      r.dot.setAttribute('cx',  String(-hw + DOT_X));
      r.sLbl.setAttribute('x', String(-hw + LBL_X));
      r.sVal.setAttribute('x', String(hw - 8));
    });
    totLbl.setAttribute('x', String(-hw + LBL_X));
    totVal.setAttribute('x', String(hw - 8));

    // divider lines
    var div1Y = bCy + hdrH + divH/2;
    var div2Y = bCy + hdrH + divH + series.length * rowH + divH/2;
    tipG.insertBefore(el('line', { x1:-hw+8, y1:div1Y, x2:hw-8, y2:div1Y, 'class':'tip-divider' }), qLbl.nextSibling);
    tipG.appendChild(el('line',  { x1:-hw+8, y1:div2Y, x2:hw-8, y2:div2Y, 'class':'tip-divider' }));

    // ── tip-bg rect (fill only, no stroke) ──
    var ty = bCy - PAD/2, by = ty + bh;
    tipG.insertBefore(el('rect', { x:-hw, y:ty, width:hw*2, height:bh, rx:rxB, 'class':'tip-bg' }), tipG.firstChild);

    // ── tip-border: <path> not <rect> — closed rounded-rect (no tail on panel tooltip) ──
    var borderPath = 'M'+(-(hw-rxB))+','+ty
      +' L'+(hw-rxB)+','+ty+' Q'+hw+','+ty+' '+hw+','+(ty+rxB)
      +' L'+hw+','+(by-rxB)+' Q'+hw+','+by+' '+(hw-rxB)+','+by
      +' L'+(-(hw-rxB))+','+by+' Q'+(-hw)+','+by+' '+(-hw)+','+(by-rxB)
      +' L'+(-hw)+','+(ty+rxB)+' Q'+(-hw)+','+ty+' '+(-(hw-rxB))+','+ty+' Z';
    tipG.insertBefore(el('path', { d:borderPath, 'class':'tip-border' }), tipG.children[1]);

    var hx1 = Math.max(68,  x - colW);
    var hx2 = Math.min(850, x + colW);
    var hit = el('rect', { x:hx1, y:100, width:hx2-hx1, height:400,
      fill:'transparent', cursor:'crosshair', id:'hit'+qi });
    hitLayer.appendChild(hit);

    var ch = document.getElementById('ch' + qi);
    var colDots = dotsL.querySelectorAll('.col-dot[data-col="'+qi+'"]');

    hit.addEventListener('mouseenter', function(e) {
      var pt = svg.createSVGPoint(); pt.x = e.clientX; pt.y = e.clientY;
      var sp = pt.matrixTransform(svg.getScreenCTM().inverse());
      dataLayerEl.classList.add('hovering');
      dotsL.querySelectorAll('.col-dot').forEach(function(d) { d.classList.remove('active'); });
      setSeriesActive(qi, sp.y);
      allTips[qi].style.opacity = '1';
      if (ch) ch.style.opacity = '1';
    });
    hit.addEventListener('mousemove', function(e) {
      var pt = svg.createSVGPoint(); pt.x = e.clientX; pt.y = e.clientY;
      var sp = pt.matrixTransform(svg.getScreenCTM().inverse());
      setSeriesActive(qi, sp.y);
    });
    hit.addEventListener('mouseleave', function() {
      dataLayerEl.classList.remove('hovering');
      colDots.forEach(function(d) { d.classList.remove('active'); });
      clearSeriesActive();
      allTips[qi].style.opacity = '';
      if (ch) ch.style.opacity = '';
    });
  });

  function setMode(wantDark) {
    if (wantDark === isDark) return;
    isDark = wantDark;
    var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark');
      if (thumb) thumb.setAttribute('cx','52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark');
      if (thumb) thumb.setAttribute('cx','16');
      if (lbl)   lbl.textContent = 'Dark';
    }
  }

  document.getElementById('dark-toggle').addEventListener('click', function() { setMode(!isDark); });
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print'; }
  });

  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });

  /* §3 A1 — wire animationend + .visible for wave-edges (draw animation, no both fill-mode) */
  var waveEls = svg.querySelectorAll('.wave-edge');
  var waveDelays = [0, 0.25, 0.50, 0.75, 1.00]; /* w1–w5 */
  waveEls.forEach(function(el, i) {
    el.style.animation = 'drawWave 1.2s cubic-bezier(0.4,0,0.2,1) ' + waveDelays[i] + 's';
    el.addEventListener('animationend', function() {
      el.style.animation = 'none';
      el.classList.add('visible');
    }, { once: true });
  });

  /* §3 A1 — wire animationend + .visible for each area-fill */
  var areaEls = svg.querySelectorAll('.area-fill');
  var areaDelays = [0, 0.25, 0.50, 0.75, 1.00]; /* f1–f5 */
  areaEls.forEach(function(el, i) {
    el.style.animation = 'dataFadeIn 0.8s cubic-bezier(0.4,0,0.2,1) ' + areaDelays[areaEls.length - 1 - i] + 's';
    el.addEventListener('animationend', function() {
      el.style.animation = 'none';
      el.classList.add('visible');
    }, { once: true });
  });

  /* gate hover on .ready after last area animation finishes */
  setTimeout(function() { dataLayerEl.classList.add('ready'); }, (1.00 + 0.8) * 1000 + 100);

  setMode(window.location.href.indexOf('theme=dark') !== -1);
})();
//
